2	
3	import (
4		"context"
5	
6		"github.com/utilitywarehouse/telecom-mobile/pkg/handsetdb"
7		"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
8	)
9	
10	type EQDB interface {
11		Close() error
12		GetHandsets(ctx context.Context) ([]handsetdb.HandsetType, error)
13	}
14	
15	type Storage interface {
16		UpsertHandset(ctx context.Context, handset handsetdb.Handset) error
17	}
18	
19	type handsetLoader struct {
20		eqdb  EQDB
21		store Storage
22	}
23	
24	func NewHandsetLoader(eqdb EQDB, store Storage) *handsetLoader {
25		return &handsetLoader{
26			eqdb:  eqdb,
27			store: store,
28		}
29	}
30	
31	func (h *handsetLoader) Run(ctx context.Context) {
32		handsets, err := h.eqdb.GetHandsets(ctx)
33		if err != nil {
34			tlog.WithError(err).Error(ctx, "failed to get handsets from equinoxdb")
35			return
36		}
37	
38		for _, handset := range handsets {
39			if err := h.store.UpsertHandset(ctx, handsetdb.HandsetTypeToHandset(handset)); err != nil {
40				tlog.WithError(err).Error(ctx, "failed to upsert handset")
41				return
42			}
43		}
44	
45		return
46	}
