1	syntax = "proto3";
2	package handset;
3	
4	option go_package = "github.com/utilitywarehouse/telecom-mobile/services/handset/pkg/protos/generated/v1/apis/handset";
5	
6	import "google/api/annotations.proto";
7	import "protoc-gen-openapiv2/options/annotations.proto";
8	import "mobile/v1/events/service_events.proto";
9	import "google/protobuf/empty.proto";
10	import "google/protobuf/timestamp.proto";
11	
12	option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_swagger) = {
13	  info: {
14	    title: "Handset API"
15	    version: "1.0.0"
16	    contact: {
17	      name: "telecom"
18	      url: "https://github.com/utilitywarehouse/telecom-mobile"
19	      email: "telecom@uw.co.uk"
20	    }
21	  };
22	}
23	;
24	
25	service HandsetAPI {
26	  rpc GetActiveContractForService(GetActiveContractForServiceRequest)
27	      returns (GetActiveContractForServiceResponse) {
28	    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
29	      description: "gets existing handset contract for a given service"
30	    };
31	    option (google.api.http) = {
32	      get: "/v1/handsets/contracts"
33	    };
34	  }
35	  rpc GetAvailableHandsets(GetAvailableHandsetsRequest)
36	      returns (GetAvailableHandsetsResponse) {
37	    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
38	      description: "gets available handsets for order for a given service"
39	    };
40	    option (google.api.http) = {
41	      get: "/v1/handsets/available"
42	    };
43	  }
44	  rpc RequestHandsetForService(RequestHandsetForServiceRequest)
45	      returns (RequestHandsetForServiceResponse) {
46	    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
47	      description: "requests a handset for a given service"
48	    };
49	    option (google.api.http) = {
50	      post: "/v1/handsets/requests"
51	      body: "*"
52	    };
53	  }
54	  rpc EligibilityCallbackSuccess(EligibilityCallbackSuccessRequest)
55	      returns (google.protobuf.Empty) {
56	    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
57	      description: "callback endpoint for handset eligibility success response from external provider"
58	    };
59	    option (google.api.http) = {
60	      post: "/v1/handsets/eligibility/completed"
61	      body: "*"
62	    };
63	  }
64	  rpc EligibilityCallbackFailure(EligibilityCallbackFailureRequest)
65	      returns (google.protobuf.Empty) {
66	    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
67	      description: "callback endpoint for handset eligibility failure response from external provider"
68	    };
69	    option (google.api.http) = {
70	      post: "/v1/handsets/eligibility/failed"
71	      body: "*"
72	    };
73	  }
74	  rpc EligibilityStatusUpdate(EligibilityStatusUpdateRequest)
75	      returns (google.protobuf.Empty) {
76	    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
77	      description: "status update endpoint for handset eligibility response from external provider"
78	    };
79	    option (google.api.http) = {
80	      put: "/v1/handsets/eligibility/status"
81	      body: "*"
82	    };
83	  }
84	  rpc GetRequest(GetRequestRequest)
85	      returns (GetRequestResponse) {
86	    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
87	      description: "gets contract details by request ID, used by the third-party eligibility provider"
88	    };
89	    option (google.api.http) = {
90	      get: "/v1/handsets/requests/{request_id}"
91	    };
92	  }
93	}
94	
95	message GetActiveContractForServiceRequest {
96	  string service_id = 1;
97	}
98	
99	message GetActiveContractForServiceResponse {
100	  Contract contract = 1;
101	}
102	
103	message GetAvailableHandsetsRequest {
104	  string service_id = 1;
105	}
106	
107	message GetAvailableHandsetsResponse {
108	  repeated Handset handsets = 1;
109	}
110	
111	message RequestHandsetForServiceRequest {
112	  string service_id = 1;
113	  string customer_id = 2;
114	  string handset_id = 3;
115	}
116	
117	message RequestHandsetForServiceResponse {
118	  string handset_id = 1;
119	  string request_id = 2;
120	  string status = 3;
121	  string redirect_url = 4;
122	}
123	
124	message EligibilityCallbackSuccessRequest {
125	  string request_id = 1;
126	  string status = 2;
127	  EligibilityCallbackSuccessOutcome decision = 3;
128	  string agreement_id = 4;
129	  string docusign_envelope_id = 5;
130	  google.protobuf.Timestamp signed_at = 6;
131	  google.protobuf.Timestamp completed_at = 7;
132	}
133	
134	message EligibilityStatusUpdateRequest {
135	  string request_id = 1;
136	  EligibilityStatusUpdate status = 2;
137	  string status_comment = 3;
138	}
139	
140	message EligibilityCallbackFailureRequest {
141	  string request_id = 1;
142	  string status = 2;
143	  EligibilityCallbackFailureReason failure_reason = 3;
144	  EligibilityCallbackFailureStage failure_stage = 4;
145	  string failure_message = 5;
146	  google.protobuf.Timestamp failed_at = 6;
147	}
148	
