155	func (s storage) GetHandsets(ctx context.Context, isInStock bool) ([]models.Handset, error) {
156		filter := bson.M{"active": true}
157		if isInStock {
158			filter["quantityInStock"] = bson.M{"$gt": 0}
159		}
160	
161		cur, err := s.handsetsCollection.Find(ctx, filter)
162		if err != nil {
163			return nil, fmt.Errorf("could not find handsets: %w", err)
164		}
165	
166		defer func(cur *mongo.Cursor, ctx context.Context) {
167			err := cur.Close(ctx)
168			if err != nil {
169				tlog.Error(ctx, "could not close cursor: %s", err.Error())
170			}
171		}(cur, ctx)
172	
173		var handsets []models.Handset
174		for cur.Next(ctx) {
175			var handset models.Handset
176			err := cur.Decode(&handset)
177			if err != nil {
178				return nil, fmt.Errorf("could not decode handset: %w", err)
179			}
180			handsets = append(handsets, handset)
181		}
182	
183		if err := cur.Err(); err != nil {
184			return nil, fmt.Errorf("error iterating over handsets: %w", err)
185		}
186	
187		return handsets, nil
188	}
